const BMW_DATA = RAW.map(r => ({
  model: r.m, year: r.y, price: r.p, transmission: r.t,
  mileage: r.mi, fuelType: r.f, tax: r.tx, mpg: r.mpg, engineSize: r.e
}));

const BLUE="#1C6EF2",SILVER="#C0C8D8",GOLD="#C9A84C",RED="#E63946",DARK="#0A0C10",CARD="#111520",BORDER="#1E2535";
const COLORS=[BLUE,GOLD,SILVER,RED,"#6EE7B7","#F59E0B","#A78BFA"];

function parseAndExecute(query) {
  const q = query.toLowerCase().trim();
  const dangerous = ["delete","drop","truncate","insert","update","remove","hack","exec","<script","alert("];
  if (dangerous.some(w => q.includes(w))) {
    return { type:"error", message:"⚠️ That request cannot be processed. Only read-only analytical queries on the BMW inventory dataset are supported." };
  }
  const vague = ["something cool","surprise me","anything","random","whatever","show me something","i don't know","idk"];
  if (vague.some(w => q.includes(w)) || q.split(" ").length <= 2) {
    return { type:"cannot_answer", message:`I need a more specific question about the BMW inventory. Try asking about price, mileage, fuel type, model, year, or transmission — for example: "Show average price by model" or "What is the trend of mileage over the years?"` };
  }
  const avg = arr => arr.reduce((a,b)=>a+b,0)/arr.length;
  const group = (key, valKey) => {
    const g={};
    BMW_DATA.forEach(r=>{ if(!g[r[key]]) g[r[key]]=[]; g[r[key]].push(r[valKey]); });
    return g;
  };
  const fmtPrice = v => "£"+Math.round(v).toLocaleString();
  const fmtMi = v => Math.round(v).toLocaleString()+" mi";

  if ((q.includes("average")||q.includes("avg")||q.includes("mean"))&&q.includes("price")&&!q.includes("by")&&!q.includes("model")&&!q.includes("fuel")&&!q.includes("year")&&!q.includes("transmission")) {
    const a = avg(BMW_DATA.map(r=>r.price));
    return { type:"stat", label:"Average Price — All BMW Vehicles", value:"£"+Math.round(a).toLocaleString(), sub:`Based on ${BMW_DATA.length.toLocaleString()} vehicles` };
  }
  if (q.includes("price")&&(q.includes("fuel"))) {
    const g=group("fuelType","price");
    const data=Object.entries(g).map(([k,v])=>({name:k,value:Math.round(avg(v))})).sort((a,b)=>b.value-a.value);
    return { type:"bar", title:"Average Price by Fuel Type", data, xKey:"name", yKey:"value", formatter:fmtPrice };
  }
  if (q.includes("mileage")&&q.includes("year")) {
    const fuel=q.includes("diesel")?"Diesel":q.includes("petrol")?"Petrol":q.includes("electric")?"Electric":null;
    let sub=BMW_DATA; if(fuel) sub=BMW_DATA.filter(r=>r.fuelType===fuel);
    const g={};
    sub.forEach(r=>{ if(!g[r.year]) g[r.year]=[]; g[r.year].push(r.mileage); });
    const data=Object.entries(g).map(([k,v])=>({name:parseInt(k),value:Math.round(avg(v))})).sort((a,b)=>a.name-b.name).filter(d=>d.name>=2008);
    return { type:"line", title:`Average Mileage Over Years${fuel?" ("+fuel+")":""}`, data, xKey:"name", yKey:"value", formatter:fmtMi };
  }
  if (q.includes("price")&&(q.includes("model")||q.includes("series"))) {
    const g=group("model","price");
    const data=Object.entries(g).map(([k,v])=>({name:k,value:Math.round(avg(v))})).sort((a,b)=>b.value-a.value);
    return { type:"bar", title:"Average Price by Model", data, xKey:"name", yKey:"value", formatter:fmtPrice };
  }
  if ((q.includes("count")||q.includes("distribution")||q.includes("how many")||q.includes("inventory"))&&(q.includes("model")||q.includes("series"))) {
    const g={};
    BMW_DATA.forEach(r=>{ if(!g[r.model]) g[r.model]=0; g[r.model]++; });
    const data=Object.entries(g).map(([k,v])=>({name:k,value:v})).sort((a,b)=>b.value-a.value);
    return { type:"bar", title:"Inventory Count by Model", data, xKey:"name", yKey:"value", formatter:v=>v.toLocaleString() };
  }
  if ((q.includes("distribution")||q.includes("breakdown")||q.includes("proportion")||q.includes("share")||q.includes("pie"))&&q.includes("fuel")) {
    const g={};
    BMW_DATA.forEach(r=>{ if(!g[r.fuelType]) g[r.fuelType]=0; g[r.fuelType]++; });
    const data=Object.entries(g).map(([k,v])=>({name:k,value:v})).sort((a,b)=>b.value-a.value);
    return { type:"pie", title:"Fuel Type Distribution", data };
  }
  if (q.includes("transmission")) {
    const g={};
    BMW_DATA.forEach(r=>{ if(!g[r.transmission]) g[r.transmission]=0; g[r.transmission]++; });
    const data=Object.entries(g).map(([k,v])=>({name:k,value:v}));
    return { type:"pie", title:"Transmission Distribution", data };
  }
  if (q.includes("price")&&q.includes("year")) {
    const g=group("year","price");
    const data=Object.entries(g).map(([k,v])=>({name:parseInt(k),value:Math.round(avg(v))})).sort((a,b)=>a.name-b.name).filter(d=>d.name>=2010);
    return { type:"line", title:"Average Price Trend by Year", data, xKey:"name", yKey:"value", formatter:fmtPrice };
  }
  if (q.includes("mileage")&&q.includes("model")) {
    const g=group("model","mileage");
    const data=Object.entries(g).map(([k,v])=>({name:k,value:Math.round(avg(v))})).sort((a,b)=>b.value-a.value);
    return { type:"bar", title:"Average Mileage by Model", data, xKey:"name", yKey:"value", formatter:fmtMi };
  }
  if (q.includes("mpg")||q.includes("fuel efficiency")||q.includes("economy")) {
    const g={};
    BMW_DATA.forEach(r=>{ if(r.mpg>0&&r.mpg<200){ if(!g[r.model]) g[r.model]=[]; g[r.model].push(r.mpg); } });
    const data=Object.entries(g).map(([k,v])=>({name:k,value:parseFloat(avg(v).toFixed(1))})).sort((a,b)=>b.value-a.value);
    return { type:"bar", title:"Average MPG by Model", data, xKey:"name", yKey:"value", formatter:v=>v+" mpg" };
  }
  if (q.includes("engine")) {
    const g={};
    BMW_DATA.forEach(r=>{ const k=r.engineSize+"L"; if(!g[k]) g[k]=0; g[k]++; });
    const data=Object.entries(g).map(([k,v])=>({name:k,value:v})).sort((a,b)=>parseFloat(a.name)-parseFloat(b.name));
    return { type:"bar", title:"Count by Engine Size", data, xKey:"name", yKey:"value", formatter:v=>v.toLocaleString() };
  }
  if (q.includes("most expensive")||q.includes("highest price")||q.includes("top price")) {
    const top=[...BMW_DATA].sort((a,b)=>b.price-a.price).slice(0,10);
    const data=top.map(r=>({name:r.model+" '"+String(r.year).slice(-2),value:r.price}));
    return { type:"bar", title:"Top 10 Most Expensive Vehicles", data, xKey:"name", yKey:"value", formatter:fmtPrice };
  }
  if (q.includes("total")||q.includes("how many")||q.includes("count")) {
    return { type:"stat", label:"Total Vehicles in Inventory", value:BMW_DATA.length.toLocaleString(), sub:"BMW Vehicle Inventory Dataset" };
  }
  return { type:"cannot_answer", message:`I couldn't find a clear match for: "${query}". Try questions about price, mileage, fuel type, model distribution, MPG, or engine size. Example: "Show average price by model"` };
}

const Tip = ({active,payload,label,formatter}) => {
  if(!active||!payload?.length) return null;
  return <div style={{background:"#0D1018",border:"1px solid #1E2535",borderRadius:8,padding:"10px 14px"}}>
    <p style={{color:"#8892A4",fontSize:11,margin:"0 0 4px"}}>{label}</p>
    <p style={{color:GOLD,fontFamily:"'Playfair Display',serif",fontWeight:700,fontSize:15,margin:0}}>{formatter?formatter(payload[0].value):payload[0].value}</p>
  </div>;
};

function BarViz({result}) {
  return <ResponsiveContainer width="100%" height={300}>
    <BarChart data={result.data} margin={{top:10,right:20,left:10,bottom:55}}>
      <CartesianGrid strokeDasharray="3 3" stroke="#1E2535" vertical={false}/>
      <XAxis dataKey={result.xKey} tick={{fill:"#8892A4",fontSize:10}} angle={-35} textAnchor="end" interval={0}/>
      <YAxis tick={{fill:"#8892A4",fontSize:10}} tickFormatter={v=>v>=1000?Math.round(v/1000)+"k":v}/>
      <Tooltip content={<Tip formatter={result.formatter}/>} cursor={{fill:"rgba(28,110,242,0.07)"}}/>
      <Bar dataKey={result.yKey} radius={[4,4,0,0]}>{result.data.map((_,i)=><Cell key={i} fill={i===0?GOLD:BLUE} fillOpacity={i===0?1:0.78}/>)}</Bar>
    </BarChart>
  </ResponsiveContainer>;
}

function LineViz({result}) {
  return <ResponsiveContainer width="100%" height={280}>
    <LineChart data={result.data} margin={{top:10,right:24,left:10,bottom:10}}>
      <CartesianGrid strokeDasharray="3 3" stroke="#1E2535" vertical={false}/>
      <XAxis dataKey={result.xKey} tick={{fill:"#8892A4",fontSize:10}}/>
      <YAxis tick={{fill:"#8892A4",fontSize:10}} tickFormatter={v=>v>=1000?Math.round(v/1000)+"k":v}/>
      <Tooltip content={<Tip formatter={result.formatter}/>}/>
      <Line type="monotone" dataKey={result.yKey} stroke={BLUE} strokeWidth={2.5} dot={{fill:GOLD,r:4,strokeWidth:0}} activeDot={{r:6,fill:GOLD}}/>
    </LineChart>
  </ResponsiveContainer>;
}

function PieViz({result}) {
  const R=Math.PI/180;
  const lbl=({cx,cy,midAngle,innerRadius,outerRadius,percent,name})=>{
    if(percent<0.05) return null;
    const r=innerRadius+(outerRadius-innerRadius)*0.5;
    return <text x={cx+r*Math.cos(-midAngle*R)} y={cy+r*Math.sin(-midAngle*R)} fill="white" textAnchor="middle" dominantBaseline="central" fontSize={11} fontWeight={700}>{(percent*100).toFixed(0)}%</text>;
  };
  return <ResponsiveContainer width="100%" height={280}>
    <PieChart>
      <Pie data={result.data} dataKey="value" nameKey="name" cx="50%" cy="50%" outerRadius={105} labelLine={false} label={lbl}>
        {result.data.map((_,i)=><Cell key={i} fill={COLORS[i%COLORS.length]}/>)}
      </Pie>
      <Legend iconType="circle" iconSize={8} wrapperStyle={{color:"#8892A4",fontSize:11}}/>
      <Tooltip content={<Tip/>}/>
    </PieChart>
  </ResponsiveContainer>;
}

function StatCard({result}) {
  return <div style={{textAlign:"center",padding:"44px 20px"}}>
    <div style={{fontSize:11,letterSpacing:"0.15em",textTransform:"uppercase",color:"#8892A4",marginBottom:14}}>{result.label}</div>
    <div style={{fontSize:58,fontFamily:"'Playfair Display',serif",fontWeight:700,color:GOLD,letterSpacing:-1}}>{result.value}</div>
    {result.sub&&<div style={{fontSize:12,color:"#4A5568",marginTop:10}}>{result.sub}</div>}
  </div>;
}

const CHIPS=["What is the average price of all BMW vehicles?","Show average price by fuel type","What is the trend of average mileage over the years for diesel cars?","Average price by model","Distribution of fuel types","MPG comparison by model","Vehicle count by transmission","Price trend over the years","Most expensive BMW vehicles","Inventory count by model"];

const TESTS=[
  ["Query 1","What is the average price of all BMW vehicles?","single number"],
  ["Query 2","Show average price by fuel type","bar chart"],
  ["Query 3","What is the trend of average mileage over the years for diesel cars?","line chart"],
  ["Bad input","Delete all data","rejected gracefully"],
  ["Vague input","Show me something cool","cannot-answer message"],
];

export default function App() {
  const [query,setQuery]=useState("");
  const [result,setResult]=useState(null);
  const [loading,setLoading]=useState(false);
  const [history,setHistory]=useState([]);
  const [apiKey,setApiKey]=useState("");
  const [showApi,setShowApi]=useState(false);

  const run = async (q=query) => {
    if(!q.trim()) return;
    setLoading(true); setResult(null);
    await new Promise(r=>setTimeout(r,500));
    const res=parseAndExecute(q);
    setResult(res);
    setHistory(prev=>[{q,type:res.type},...prev.slice(0,19)]);
    setLoading(false);
  };

  return (
    <div style={{minHeight:"100vh",background:DARK,color:"#E8ECF4",fontFamily:"'DM Sans',sans-serif",display:"flex",flexDirection:"column",backgroundImage:"radial-gradient(ellipse at 15% 15%,rgba(28,110,242,0.07) 0%,transparent 55%),radial-gradient(ellipse at 85% 85%,rgba(201,168,76,0.05) 0%,transparent 55%)"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;700;900&family=DM+Sans:wght@300;400;500&family=JetBrains+Mono:wght@400;500&display=swap');
        *{box-sizing:border-box;} ::-webkit-scrollbar{width:4px} ::-webkit-scrollbar-track{background:#0A0C10} ::-webkit-scrollbar-thumb{background:#1E2535;border-radius:4px}
        .chip:hover{background:rgba(28,110,242,0.15)!important;border-color:#1C6EF2!important;color:white!important;transform:translateY(-1px)}
        .sbtn:hover{background:#1557D0!important}
        .hitem:hover{background:rgba(28,110,242,0.08)!important;border-color:rgba(28,110,242,0.3)!important}
        .trow:hover{background:rgba(201,168,76,0.05)!important;cursor:pointer}
        .fade-in{animation:fi 0.35s ease forwards} @keyframes fi{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}
        .pulse{animation:p 1.4s ease-in-out infinite} @keyframes p{0%,100%{opacity:1}50%{opacity:0.3}}
      `}</style>

      <div style={{display:"flex",height:"100vh",overflow:"hidden"}}>

        {/* Sidebar */}
        <div style={{width:248,background:"#080A0F",borderRight:"1px solid #1E2535",display:"flex",flexDirection:"column",flexShrink:0}}>
          <div style={{padding:"22px 20px 18px",borderBottom:"1px solid #1E2535"}}>
            <div style={{display:"flex",alignItems:"center",gap:10}}>
              <div style={{width:34,height:34,borderRadius:"50%",background:"linear-gradient(135deg,#1C6EF2 0%,#0a1628 100%)",border:"1.5px solid #1C6EF2",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,fontWeight:800,color:"white",letterSpacing:-1}}>B</div>
              <div>
                <div style={{fontSize:13,fontWeight:600,letterSpacing:"0.04em"}}>BMW Analytics</div>
                <div style={{fontSize:9,color:"#4A5568",letterSpacing:"0.12em",textTransform:"uppercase"}}>Intelligence Suite</div>
              </div>
            </div>
          </div>

          <div style={{padding:"14px 18px",borderBottom:"1px solid #1E2535"}}>
            <div style={{fontSize:9,color:"#4A5568",letterSpacing:"0.14em",textTransform:"uppercase",marginBottom:10}}>Dataset Overview</div>
            {[["Records","10,781"],["Models","24"],["Year Range","1996–2020"],["Fuel Types","5"]].map(([k,v])=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                <span style={{fontSize:11,color:"#8892A4"}}>{k}</span>
                <span style={{fontSize:11,color:GOLD,fontFamily:"'JetBrains Mono',monospace"}}>{v}</span>
              </div>
            ))}
          </div>

          <div style={{flex:1,overflow:"auto",padding:"14px 12px"}}>
            <div style={{fontSize:9,color:"#4A5568",letterSpacing:"0.14em",textTransform:"uppercase",marginBottom:8,paddingLeft:4}}>Recent Queries</div>
            {history.length===0 && <div style={{fontSize:11,color:"#2D3748",padding:"0 4px"}}>No queries yet</div>}
            {history.map((h,i)=>(
              <button key={i} className="hitem" onClick={()=>{setQuery(h.q);run(h.q);}} style={{background:"transparent",border:"1px solid #1E2535",borderRadius:7,padding:"7px 10px",cursor:"pointer",textAlign:"left",width:"100%",marginBottom:3,transition:"all 0.15s"}}>
                <div style={{fontSize:10,color:"#8892A4",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{h.q}</div>
                <div style={{fontSize:9,color:"#4A5568",marginTop:2,textTransform:"uppercase",letterSpacing:"0.08em"}}>{h.type}</div>
              </button>
            ))}
          </div>

          <div style={{padding:"12px 14px",borderTop:"1px solid #1E2535"}}>
            <button onClick={()=>setShowApi(!showApi)} style={{background:"transparent",border:"1px solid #1E2535",borderRadius:6,padding:"7px 10px",cursor:"pointer",color:apiKey?"#6EE7B7":"#8892A4",fontSize:10,width:"100%",display:"flex",alignItems:"center",gap:6,fontFamily:"'DM Sans',sans-serif"}}>
              <span>{apiKey?"●":"○"}</span>{apiKey?"Gemini Connected":"Configure Gemini API"}
            </button>
            {showApi&&<div style={{marginTop:7}}>
              <input value={apiKey} onChange={e=>setApiKey(e.target.value)} placeholder="AIza..." style={{width:"100%",background:CARD,border:"1px solid #1E2535",borderRadius:5,padding:"7px 9px",color:"#E8ECF4",fontSize:10,outline:"none",fontFamily:"'JetBrains Mono',monospace"}}/>
              <div style={{fontSize:9,color:"#4A5568",marginTop:4}}>For enhanced NL query understanding</div>
            </div>}
          </div>
        </div>

        {/* Main */}
        <div style={{flex:1,display:"flex",flexDirection:"column",overflow:"hidden"}}>
          <div style={{padding:"18px 28px",borderBottom:"1px solid #1E2535",display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
            <div>
              <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:20,fontWeight:700,margin:0,letterSpacing:-0.3}}>
                Conversational <span style={{color:BLUE}}>BI</span> Dashboard
              </h1>
              <p style={{fontSize:11,color:"#8892A4",margin:"2px 0 0"}}>Ask anything about BMW vehicle inventory in plain English</p>
            </div>
            <div style={{fontSize:10,color:"#4A5568",fontFamily:"'JetBrains Mono',monospace",textAlign:"right"}}>
              <div>{BMW_DATA.length.toLocaleString()} vehicles</div>
              <div style={{color:"#2D3748"}}>loaded ✓</div>
            </div>
          </div>

          <div style={{flex:1,overflow:"auto",padding:"20px 28px"}}>
            {(result||loading)&&(
              <div className="fade-in" style={{background:CARD,border:"1px solid #1E2535",borderRadius:12,marginBottom:22,overflow:"hidden"}}>
                {loading?(
                  <div style={{padding:44,textAlign:"center"}}>
                    <div className="pulse" style={{fontSize:12,color:"#8892A4",letterSpacing:"0.15em",textTransform:"uppercase"}}>● Analyzing query</div>
                    <div style={{marginTop:10,fontSize:11,color:"#2D3748"}}>Processing natural language...</div>
                  </div>
                ):result?.type==="error"?(
                  <div style={{padding:24,display:"flex",gap:14,alignItems:"flex-start"}}>
                    <div style={{fontSize:22,flexShrink:0}}>🚫</div>
                    <div>
                      <div style={{fontSize:13,fontWeight:600,color:RED,marginBottom:5}}>Request Rejected</div>
                      <div style={{fontSize:13,color:"#8892A4",lineHeight:1.65}}>{result.message}</div>
                    </div>
                  </div>
                ):result?.type==="cannot_answer"?(
                  <div style={{padding:24,display:"flex",gap:14,alignItems:"flex-start"}}>
                    <div style={{fontSize:22,flexShrink:0}}>💡</div>
                    <div>
                      <div style={{fontSize:13,fontWeight:600,color:GOLD,marginBottom:5}}>Cannot Answer</div>
                      <div style={{fontSize:13,color:"#8892A4",lineHeight:1.65}}>{result.message}</div>
                    </div>
                  </div>
                ):result?.type==="stat"?(
                  <StatCard result={result}/>
                ):(
                  <div>
                    <div style={{padding:"18px 22px 4px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                      <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:16,margin:0,fontWeight:700}}>{result?.title}</h2>
                      <span style={{fontSize:9,color:"#4A5568",background:"#0A0C10",border:"1px solid #1E2535",borderRadius:4,padding:"3px 8px",textTransform:"uppercase",letterSpacing:"0.1em"}}>{result?.type} chart</span>
                    </div>
                    <div style={{padding:"8px 4px 14px"}}>
                      {result?.type==="bar"&&<BarViz result={result}/>}
                      {result?.type==="line"&&<LineViz result={result}/>}
                      {result?.type==="pie"&&<PieViz result={result}/>}
                    </div>
                  </div>
                )}
              </div>
            )}

            {!result&&!loading&&(
              <>
                <div style={{marginBottom:20}}>
                  <div style={{fontSize:9,color:"#4A5568",letterSpacing:"0.14em",textTransform:"uppercase",marginBottom:12}}>Try these queries</div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:7}}>
                    {CHIPS.map((s,i)=>(
                      <button key={i} className="chip" onClick={()=>{setQuery(s);run(s);}} style={{background:"rgba(28,110,242,0.06)",border:"1px solid #1E2535",borderRadius:20,padding:"6px 13px",cursor:"pointer",fontSize:11,color:"#8892A4",transition:"all 0.15s",fontFamily:"'DM Sans',sans-serif"}}>
                        {s}
                      </button>
                    ))}
                  </div>
                </div>

                <div style={{background:"rgba(201,168,76,0.04)",border:"1px solid rgba(201,168,76,0.12)",borderRadius:10,padding:"16px 20px"}}>
                  <div style={{fontSize:9,color:GOLD,letterSpacing:"0.15em",textTransform:"uppercase",marginBottom:12}}>✓ Testing Checklist</div>
                  {TESTS.map(([label,q,exp])=>(
                    <div key={q} className="trow" onClick={()=>{setQuery(q);run(q);}} style={{display:"flex",alignItems:"flex-start",gap:10,padding:"6px 8px",borderRadius:6,transition:"background 0.15s",marginBottom:2}}>
                      <div style={{width:14,height:14,border:"1.5px solid #2D3748",borderRadius:3,flexShrink:0,marginTop:1}}/>
                      <div style={{fontSize:12,lineHeight:1.5}}>
                        <span style={{color:"#4A5568"}}>{label}: </span>
                        <span style={{color:SILVER}}>"{q}"</span>
                        <span style={{color:"#4A5568"}}> → {exp}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>

          {/* Input */}
          <div style={{padding:"14px 28px 20px",borderTop:"1px solid #1E2535",background:"#080A0F",flexShrink:0}}>
            <div style={{display:"flex",gap:8,background:CARD,border:"1px solid #1E2535",borderRadius:10,padding:"5px 6px 5px 16px"}}>
              <input
                value={query}
                onChange={e=>setQuery(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&run()}
                placeholder="Ask a business question about BMW inventory..."
                style={{flex:1,background:"transparent",border:"none",outline:"none",color:"#E8ECF4",fontSize:13,fontFamily:"'DM Sans',sans-serif",lineHeight:1.5}}
              />
              <button className="sbtn" onClick={()=>run()} disabled={loading||!query.trim()} style={{background:BLUE,border:"none",borderRadius:7,padding:"9px 18px",cursor:loading?"not-allowed":"pointer",color:"white",fontSize:12,fontWeight:500,fontFamily:"'DM Sans',sans-serif",opacity:(!query.trim()||loading)?0.4:1,transition:"all 0.15s"}}>
                {loading?"●●●":"Analyze →"}
              </button>
            </div>
            <div style={{fontSize:10,color:"#2D3748",marginTop:7,textAlign:"center"}}>
              BMW Vehicle Inventory · 10,781 records · Natural Language Analytics Engine
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
